"""
MKT Christ Commentary — 1 Chronicles chapter 29
Run: python3 scripts/zc-christ-1chronicles-29-29.py

Ch29: David's final chapter — freewill offerings for the temple (29:1-9);
      David's doxology "yours is the kingdom" (29:11; source of Matt 6:13 doxology);
      "from you and of your own we give you" (29:14; Rom 11:36 parallel);
      sojourner theology (29:15); Solomon on YHWH's throne (29:23); David's death (29:28)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "29": {
    "1": "<p>David said to the whole assembly: &lsquo;Solomon my son, whom alone God has chosen, is young and inexperienced, and the work is great.&rsquo; The divine choice of the son for the temple-building — &lsquo;God has chosen&rsquo; (<em>ʾelōhîm bāḥar bᵉ</em>) — places Solomon&rsquo;s selection in the line of divine election that runs from Abel to Isaac to Jacob to David to Solomon. John 3:16-17: &lsquo;God so loved the world, that he gave his only Son&rsquo; — the divine choice of the Son for the redemption-work mirrors the divine choice of Solomon for the temple-work. The &lsquo;young and inexperienced&rsquo; qualifier mirrors the NT&rsquo;s consistent pattern of divine selection of the inadequate for covenant purposes (1 Cor 1:27-29).</p>",
    "2": "<p>David devoted tremendous resources to the temple project — gold, silver, bronze, iron, wood, onyx, marble, and precious stones. The lavish material provision David assembled for a house he would never build is a type of the preparation that preceded the Incarnation: generations of covenant history, prophecy, law, and worship assembled the context into which the Son would come. Heb 1:1-2: &lsquo;In many and various ways God spoke to our fathers by the prophets, but in these last days he has spoken to us by his Son.&rsquo; The preparatory work was immense; the arrival of the Son was the temple&rsquo;s true fulfillment.</p>",
    "3": "<p>David also gave from his personal treasure — gold and silver beyond the public treasury. The king gives above and beyond the official levy: his personal resources given freely for the house of God. 2 Cor 8:9: &lsquo;though he was rich, yet for your sake he became poor.&rsquo; Christ gave his own personal divine richness — infinite resources — for the construction of the true temple (his people); the giving of the king&rsquo;s private treasure for the house of God is a type of the Son&rsquo;s self-emptying (Phil 2:7) for the covenant community.</p>",
    "4": "<p>Gold from Ophir — 3,000 talents — and refined silver for overlaying the walls. The specific quality of the gold (&lsquo;refined gold of Ophir&rsquo;, <em>zāhāḇ ʾôpîr</em>) for the most honored surfaces of the sanctuary. Rev 21:18-21: the new Jerusalem is &lsquo;pure gold, like clear glass&rsquo; — the golden sanctuary of the Solomonic temple is the OT type of the eschatological city of gold where God&rsquo;s dwelling with his people is finally realized.</p>",
    "5": "<p>&lsquo;Who then will offer willingly, consecrating himself today to YHWH?&rsquo; David&rsquo;s call for freewill offerings frames the offering as an act of self-consecration to YHWH — giving oneself in the giving of resources. Rom 12:1: &lsquo;I appeal to you therefore, brothers, by the mercies of God, to present your bodies as a living sacrifice, holy and acceptable to God, which is your spiritual worship.&rsquo; The self-consecration-through-material-giving that David calls for is the OT form of Paul&rsquo;s call for the living-sacrifice of the whole self. Both are responses to divine generosity.</p>",
    "6": "<p>Then the leaders of fathers&rsquo; houses made freewill offerings, as did the commanders of thousands and hundreds, and the officers over the king&rsquo;s work. The whole leadership structure of Israel responds to the king&rsquo;s call — military, administrative, and civic leaders all giving. The Church&rsquo;s generosity similarly flows from the top of its structure outward: when leaders model freewill giving, the whole community is energized (2 Cor 9:2: &lsquo;your zeal has stirred up most of them&rsquo;).</p>",
    "7": "<p>They gave for the service of the house of God 5,000 talents and 10,000 darics of gold, 10,000 talents of silver, 18,000 talents of bronze, and 100,000 talents of iron. The staggering amounts — calculated in modern terms as hundreds of tons of precious metals — show the covenant community&rsquo;s total engagement in the temple project. Luke 21:1-4: Jesus contrasted the huge gifts of the wealthy with the widow&rsquo;s two copper coins — &lsquo;she out of her poverty put in all she had.&rsquo; Both the abundance of leadership giving and the total surrender of the poor are honored in the Messianic community&rsquo;s economy.</p>",
    "8": "<p>Whoever had precious stones gave them to the treasury of the house of YHWH, in the care of Jehiel the Gershonite. The inclusivity of the offering: even those with non-metal wealth (precious stones) are included in the freewill offering. The NT community&rsquo;s diversity of gifts mirrors this: &lsquo;having gifts that differ according to the grace given to us, let us use them&rsquo; (Rom 12:6). Every kind of resource and ability is included in the covenant community&rsquo;s corporate giving toward the King&rsquo;s purposes.</p>",
    "9": "<p>Then the people rejoiced because they had given willingly, for with a whole heart they had offered freely to YHWH. The joy of freewill giving — the response to the covenant community&rsquo;s own generosity is joy. 2 Cor 9:7: &lsquo;Each one must give as he has decided in his heart, not reluctantly or under compulsion, for God loves a cheerful giver.&rsquo; The joy of ch 29&rsquo;s offering-assembly (&lsquo;the people rejoiced... with a whole heart&rsquo;) is the OT form of the NT&rsquo;s &lsquo;cheerful giver&rsquo; theology. The whole-heart offering produces whole-heart joy.</p>",
    "10": "<p>David blessed YHWH in the sight of all the assembly: &lsquo;Blessed are you, O YHWH, the God of Israel our father, forever and ever.&rsquo; David&rsquo;s prayer opens with the Jewish <em>berāḵāh</em> (blessing) form — the pattern of Jewish prayer that begins by blessing (acknowledging the worth of) YHWH before making any petition. The &lsquo;forever and ever&rsquo; (<em>mēhāʿôlām wᵉʿaḏ hāʿôlām</em>) of the blessing doxology is the temporal frame of the NT&rsquo;s worship of Christ: &lsquo;to him be glory forever and ever&rsquo; (Gal 1:5; Phil 4:20; 1 Tim 1:17; Heb 13:21; Rev 1:6).</p>",
    "11": "<p>&lsquo;Yours, O YHWH, is the greatness and the power and the glory and the victory and the majesty, for all that is in the heavens and in the earth is yours. Yours is the kingdom, O YHWH, and you are exalted as head above all.&rsquo; This verse is the OT source of the doxology appended to the Lord&rsquo;s Prayer in many manuscripts of Matt 6:13: &lsquo;for yours is the kingdom and the power and the glory forever.&rsquo; The textual lineage is direct: the <em>hattᵉfillah</em> (the Prayer) closes in the Matthean tradition with a doxology drawn from David&rsquo;s temple-dedication prayer. The five attributes — greatness, power, glory, victory, majesty — plus &lsquo;all in heaven and earth is yours&rsquo; — form the universal sovereignty claim that Christ inherits: &lsquo;All authority in heaven and on earth has been given to me&rsquo; (Matt 28:18).</p>",
    "12": "<p>&lsquo;Both riches and honor come from you, and you rule over all. In your hand are power and might, and in your hand it is to make great and to give strength to all.&rsquo; All sovereignty is derivative from YHWH — riches, honor, power, might, greatness all proceed from him. Jas 1:17: &lsquo;every good gift and every perfect gift is from above, coming down from the Father of lights.&rsquo; The cosmic gift-source theology of David&rsquo;s prayer is the foundation of the NT&rsquo;s consistent attribution of all good things to God — and specifically to the God who gave his Son (Rom 8:32: &lsquo;he who did not spare his own Son but gave him up for us all, how will he not also with him graciously give us all things?&rsquo;).</p>",
    "13": "<p>&lsquo;And now we thank you, our God, and praise your glorious name.&rsquo; The thanksgiving response to the sovereignty-declaration — because all things come from YHWH, gratitude is the only appropriate response. Col 3:17: &lsquo;whatever you do, in word or deed, do everything in the name of the Lord Jesus, giving thanks to God the Father through him.&rsquo; The thanksgiving that David models in the temple-preparation prayer is the form of life Paul calls for in the new covenant community: continual gratitude as the response to continual divine gift.</p>",
    "14": "<p>&lsquo;But who am I, and what is my people, that we should be able thus to offer willingly? For all things come from you, and of your own have we given you.&rsquo; The theological heart of the freewill-offering prayer: everything given to YHWH is first received from YHWH — the gift-circle has God as both origin and terminus. Rom 11:35-36: &lsquo;Or who has given a gift to him that he might be repaid? For from him and through him and to him are all things. To him be glory forever.&rsquo; Paul&rsquo;s doxology at the end of Romans 9-11 quotes Job 41:11 but echoes David&rsquo;s prayer here: the cosmic gift-circle (&lsquo;from him and through him and to him&rsquo;) is the theological climax of both the Davidic prayer and the Pauline doxology. The freewill offering of the covenant community is only possible because YHWH is the prior giver of all things — including the Son who is the ultimate gift (John 3:16).</p>",
    "15": "<p>&lsquo;For we are strangers before you and sojourners, as all our fathers were. Our days on the earth are like a shadow, and there is no abiding.&rsquo; The sojourner-theology embedded in the temple-dedication prayer: even in the act of building the most permanent structure in Israel&rsquo;s history, David confesses that the builders are themselves temporary. 1 Pet 2:11: &lsquo;I urge you as sojourners and exiles to abstain from the passions of the flesh.&rsquo; Heb 11:13: &lsquo;These all died in faith, not having received the things promised, but having seen them and greeted them from afar, and having acknowledged that they were strangers and exiles on the earth.&rsquo; The NT reclaims this sojourner-identity as the permanent status of the covenant community: not resident-citizens of this age but those who &lsquo;are looking for the city that is to come&rsquo; (Heb 13:14).</p>",
    "16": "<p>&lsquo;O YHWH our God, all this abundance that we have provided for building you a house for your holy name comes from your hand and is all your own.&rsquo; The gift-circle closes: the abundance for the house has come from YHWH&rsquo;s hand and belongs to YHWH. The temple-building is YHWH&rsquo;s own project, funded from his own resources, carried out by his own chosen instruments. John 17:6-10: Christ prays that his disciples whom the Father has given him belong to the Father — the covenant community is YHWH&rsquo;s own, returned to him through the Son&rsquo;s mission.</p>",
    "17": "<p>&lsquo;I know, my God, that you test the heart and have pleasure in uprightness. In the uprightness of my heart I have freely offered all these things.&rsquo; YHWH&rsquo;s heart-testing — the divine examination of interior motivation, not merely exterior action. Rom 8:27: &lsquo;he who searches hearts knows what is the mind of the Spirit, because the Spirit intercedes for the saints according to the will of God.&rsquo; The Spirit who intercedes and the Father who searches hearts form the inner-divine knowing that Christ&rsquo;s intercession enables: the Spirit searches us; the Father accepts the Spirit-formed prayers; Christ mediates the whole. David&rsquo;s confidence that the heart-testing God knows his uprightness is the OT model of the NT&rsquo;s confidence before the heart-searching God.</p>",
    "18": "<p>&lsquo;O YHWH, the God of Abraham, Isaac, and Israel, our fathers, keep forever such purposes and thoughts in the hearts of your people, and direct their hearts toward you.&rsquo; David prays for the perpetuation of the freewill-offering heart — that the willingness of this moment would continue forever. Ezek 36:26-27: &lsquo;I will give you a new heart and a new spirit I will put within you... and I will put my Spirit within you, and cause you to walk in my statutes.&rsquo; The heart-direction David prays for is what YHWH promises through Ezekiel as the new covenant gift: the hearts of the covenant community permanently directed toward God by the indwelling Spirit.</p>",
    "19": "<p>&lsquo;Grant to Solomon my son a whole heart to keep your commandments, your testimonies, and your statutes, performing all, and that he may build the palace for which I have made provision.&rsquo; David&rsquo;s final prayer for his son: a whole heart (<em>lēḇāḇ šālēm</em>) to obey YHWH. The tragedy of Solomon&rsquo;s reign is that his heart was not whole — it was divided by foreign wives (1 Kgs 11:4: &lsquo;his heart was not wholly true to YHWH his God, as was the heart of David his father&rsquo;). The prayer was not fully answered in Solomon. It is answered in the greater Solomon: Christ, who &lsquo;learned obedience through what he suffered&rsquo; (Heb 5:8) and whose heart toward the Father was without division — the whole-heart obedience that YHWH sought in the Davidic dynasty was finally given by the Son in whom the Father was &lsquo;well pleased&rsquo; (Matt 3:17).</p>",
    "20": "<p>Then David said to all the assembly: &lsquo;Bless YHWH your God.&rsquo; And all the assembly blessed YHWH, the God of their fathers, and bowed their heads and paid homage to YHWH and to the king. The congregation&rsquo;s double homage — to YHWH and to the king simultaneously — is the OT type of the NT&rsquo;s confession that honors both the Father and the Son: &lsquo;whoever does not honor the Son does not honor the Father who sent him&rsquo; (John 5:23). The bowing before YHWH and the king together anticipates the eschatological scene where every knee bows at the name of Jesus to the glory of God the Father (Phil 2:10-11).</p>",
    "21": "<p>They offered burnt offerings to YHWH, 1,000 bulls, 1,000 rams, 1,000 lambs, with their drink offerings, and sacrifices in abundance for all Israel. The thousand-fold sacrifice at the temple-dedication assembly is a superlative act of covenant worship — a sacrifice on the scale of the covenant community&rsquo;s thanksgiving. Heb 10:10-14: Christ&rsquo;s single sacrifice surpasses all the sacrificed animals in every assembly of Israel: &lsquo;by that will we have been sanctified through the offering of the body of Jesus Christ once for all.&rsquo; The multiplication of sacrifices in the OT points toward the one sacrifice that makes all others unnecessary.</p>",
    "22": "<p>And they ate and drank before YHWH on that day with great gladness. And they made Solomon the son of David king the second time, and anointed him as prince for YHWH, and Zadok as priest. Solomon&rsquo;s second anointing — the first was private/preliminary (1 Chr 23:1); this is the public installation. The feast before YHWH and the double anointing prefigure the Messianic banquet and Christ&rsquo;s double identification: Luke 4:18 (&lsquo;the Spirit of YHWH is upon me, because he has anointed me&rsquo;) is the anointing of the Son; Rev 19:9 (&lsquo;blessed are those who are invited to the marriage supper of the Lamb&rsquo;) is the eschatological feast at the King&rsquo;s coronation.</p>",
    "23": "<p>Then Solomon sat on the throne of YHWH as king instead of David his father. The throne on which Solomon sits is explicitly called &lsquo;the throne of YHWH&rsquo; (<em>kissēʾ YHWH</em>) — not merely David&rsquo;s throne but YHWH&rsquo;s own throne. Matt 19:28: &lsquo;when the Son of Man sits on his glorious throne&rsquo; — Christ&rsquo;s throne is also YHWH&rsquo;s throne. Rev 3:21: &lsquo;the one who conquers, I will grant him to sit with me on my throne, as I also conquered and sat down with my Father on his throne.&rsquo; Solomon on YHWH&rsquo;s throne is the OT type of Christ on the Father&rsquo;s throne — and both share their throne with the covenant community.</p>",
    "24": "<p>All the leaders and the mighty men, and also all the sons of King David, pledged their allegiance to King Solomon. The voluntary submission of the whole power-structure of Israel — including David&rsquo;s own other sons (potential rivals) — to the divinely chosen successor. Phil 2:10-11: &lsquo;at the name of Jesus every knee should bow, in heaven and on earth and under the earth, and every tongue confess that Jesus Christ is Lord.&rsquo; The voluntary covenant-submission of David&rsquo;s sons to Solomon is a type of the universal acknowledgment of the greater Son&rsquo;s sovereignty.</p>",
    "25": "<p>And YHWH made Solomon very great in the sight of all Israel and bestowed on him such royal majesty as had not been on any king before him in Israel. The divine exaltation of the covenant-chosen king — YHWH makes him great. Phil 2:9: &lsquo;Therefore God has highly exalted him and bestowed on him the name that is above every name.&rsquo; Solomon&rsquo;s unprecedented royal majesty in Israel is the OT type of Christ&rsquo;s unprecedented exaltation in the cosmos: no name before or after compares to the name above all names given to the risen Christ.</p>",
    "26": "<p>David the son of Jesse reigned over all Israel. The summary of David&rsquo;s reign after the succession is established. The full pan-Israel reign of David — from all-Israel anointing (ch 12) to the well-ordered succession (ch 29) — is the type of Christ&rsquo;s universal reign from his resurrection to his return. Luke 1:32-33: &lsquo;he will reign over the house of Jacob forever, and of his kingdom there will be no end.&rsquo;</p>",
    "27": "<p>The time that he reigned over Israel was forty years. He reigned seven years in Hebron and thirty-three years in Jerusalem. David&rsquo;s forty-year reign is the full covenant-generation number (forty years in the wilderness, forty years of Saul&rsquo;s reign, forty years of David). The Hebron/Jerusalem division (7 + 33 = 40) marks David&rsquo;s reign as a complete covenant epoch. Christ&rsquo;s earthly ministry (approximately 33 years) equals David&rsquo;s Jerusalem reign — a convergence the Church Fathers noted: Christ lived as many years as David reigned in the covenant city.</p>",
    "28": "<p>He died in a good old age, full of days, riches, and honor. And Solomon his son reigned in his place. The blessed death of the covenant king — fullness of days, riches, and honor. The Chronicler&rsquo;s idealized portrait of David&rsquo;s death (omitting the deathbed bitterness of 1 Kgs 2:1-9) presents David as a king who completed his mission. Christ&rsquo;s death is the opposite of &lsquo;full of days&rsquo; (crucified at approximately 33) and of riches (he had nowhere to lay his head, Matt 8:20) — but his death is the fullest possible death because it is fully accomplished (&lsquo;it is finished,&rsquo; John 19:30). The Messianic death reverses David&rsquo;s death: not blessed rest but sacrificial self-giving — and then the resurrection reversal that is greater than David&rsquo;s natural fullness of days.</p>",
    "29": "<p>Now the acts of King David, from first to last, are written in the Chronicles of Samuel the seer, and in the Chronicles of Nathan the prophet, and in the Chronicles of Gad the seer. The three-prophet record of David&rsquo;s reign: Samuel, Nathan, and Gad. The prophetic witness to the Davidic reign is the OT pattern for the NT&rsquo;s three-witness tradition (&lsquo;a matter shall be confirmed by two or three witnesses,&rsquo; Deut 19:15; Matt 18:16; 2 Cor 13:1). The four Gospels are the new-covenant chronicles of the greater David&rsquo;s reign, from first to last — and their prophetic testimony confirms by multiple witnesses the life, death, and resurrection of the Son of David.</p>",
    "30": "<p>With all his reign and his might and the circumstances that came upon him and upon Israel and upon all the kingdoms of the countries. The reign of David is set in its full world-historical context — not Israel alone but &lsquo;all the kingdoms of the countries.&rsquo; The Davidic covenant&rsquo;s scope was never merely national; from the beginning, the promise embedded it in world history (&lsquo;in your offspring all the nations of the earth shall be blessed,&rsquo; Gen 22:18 — the Abrahamic horizon). 1 Chronicles closes with David&rsquo;s death and Solomon&rsquo;s succession — the shadow of the greater Solomon whose reign will encompass all kingdoms and all nations, and of whose government and peace there will be no end (Isa 9:7).</p>"
  }
}

def main():
    c = load_comm('mkt-christ', '1chronicles')
    merge_comm(c, CHRIST)
    save_comm('mkt-christ', '1chronicles', c)
    count = sum(len(v) for v in CHRIST.values())
    print(f'1chronicles mkt-christ: wrote {count} verses across ch 29')

if __name__ == '__main__':
    main()
